class Solution:
    def countLargestGroup(self, n):
        from collections import defaultdict
        def digit_sum(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s
        groups = defaultdict(int)
        for i in range(1, n + 1):
            groups[digit_sum(i)] += 1
        max_sz = max(groups.values())
        return sum(1 for v in groups.values() if v == max_sz)

