var countLargestGroup = function(n) {
    const groups = new Map();
    for (let i = 1; i <= n; i++) {
        let s = 0, x = i;
        while (x > 0) { s += x % 10; x = Math.floor(x / 10); }
        groups.set(s, (groups.get(s) || 0) + 1);
    }
    let maxSz = 0;
    for (const v of groups.values()) maxSz = Math.max(maxSz, v);
    let count = 0;
    for (const v of groups.values()) if (v === maxSz) count++;
    return count;
};
